// Broadcast Resolver - Topics pinned from client_mappings
const item = $input.item.json;
const msg = item.message || 'Signal pulse.';
const MAPS = [
  { name: 'promo', to: '-1003728720677:topic:1239', key: 'agent:promo:telegram:group:-1003728720677:topic:1239' },
  { name: 'main', to: '-1003728720677:topic:1', key: 'agent:main:telegram:group:-1003728720677:topic:1' },
  { name: 'digit', to: '-1003728720677:topic:3', key: 'agent:digit:telegram:group:-1003728720677:topic:3' },
  { name: 'string', to: '-1003728720677:topic:2', key: 'agent:string:telegram:group:-1003728720677:topic:2' }
];
return MAPS.map(m => ({ json: { ...m, message: msg, original: item } }));

// Unified Aggregator - Consolidates all branches before final logging
const all = $input.all();
const first = all[0].json;
const orig = first.original || first;
return {
  json: {
    event_type: 'mission_pulse',
    description: orig.message || 'Unified signal verified.',
    metadata: { version: '5.1.17', branch_count: all.length }
  }
};

